// ==================== SINGLE-DATE PROCESSING ====================
function saveEnergyDataAtMidnight(dateStr) {
  // dateStr example: '2025-08-03'
  if (!dateStr) {
    Logger.log("Please provide a date string in format YYYY-MM-DD");
    return;
  }
  processSingleDate(dateStr);
}

// ==================== FULL-YEAR / RANGE PROCESSING ====================
function saveEnergyDataForYearToDate() {
  const startDate = new Date('2025-07-14T00:00:00'); // Start of 2025 July 14th
  const today = new Date();

  for (let d = new Date(startDate); d <= today; d.setDate(d.getDate() + 1)) {
    const dateStr = Utilities.formatDate(d, Session.getScriptTimeZone(), 'yyyy-MM-dd');
    processSingleDate(dateStr);
  }

  Logger.log('All available dates processed.');
}

// ==================== CORE PROCESSING FUNCTION ====================
function processSingleDate(dateStr) {
  // --- Folder IDs ---
  const sourceRootId = '1tFigxxERpAyYbmwXsW-nXpTLl31NLyYz'; // Historian folder
  const outputFolderId = '19_FW3-Q7chQwNmGHWlsBQQj9KFsgViLL'; // Destination folder

  // --- Get folders ---
  const sourceRoot = DriveApp.getFolderById(sourceRootId);
  const outputFolder = DriveApp.getFolderById(outputFolderId);

  const targetFileName = `data_${dateStr}_00-00.json`;
  const file = findFileRecursive(sourceRoot, targetFileName);

  if (!file) {
    Logger.log(`Skipping ${dateStr}: file not found`);
    return;
  }

  try {
    const content = file.getBlob().getDataAsString();
    const jsonData = JSON.parse(content);
    const fileKey = Object.keys(jsonData)[0];
    const data = jsonData[fileKey];

    if (!data) {
      Logger.log(`Skipping ${dateStr}: no meter data`);
      return;
    }

    const result = {};
    for (const meterId in data) {
      const readings = data[meterId];
      if (Array.isArray(readings) && readings.length > 0) {
        const lastItem = readings[readings.length - 1];
        result[meterId] = lastItem;
      }
    }

    if (Object.keys(result).length === 0) {
      Logger.log(`Skipping ${dateStr}: no valid meter data`);
      return;
    }

    // --- Prepare output JSON ---
    const outputData = {};
    outputData[dateStr] = result;
    const jsonString = JSON.stringify(outputData, null, 2);
    const outputFileName = `energy_${dateStr}.json`;

    // --- Create file if not already exists ---
    if (!fileExistsInFolder(outputFolder, outputFileName)) {
      outputFolder.createFile(outputFileName, jsonString, 'application/json');
      Logger.log(`Saved: ${outputFileName}`);
    } else {
      Logger.log(`Already exists: ${outputFileName}`);
    }

  } catch (err) {
    Logger.log(`Error processing ${dateStr}: ${err}`);
  }
}

// ==================== HELPER FUNCTIONS ====================
function findFileRecursive(folder, targetFileName) {
  const files = folder.getFilesByName(targetFileName);
  if (files.hasNext()) return files.next();

  const subfolders = folder.getFolders();
  while (subfolders.hasNext()) {
    const sub = subfolders.next();
    const found = findFileRecursive(sub, targetFileName);
    if (found) return found;
  }
  return null;
}

function fileExistsInFolder(folder, fileName) {
  const files = folder.getFilesByName(fileName);
  return files.hasNext();
}
